     1→import { useState, useCallback, useRef, useEffect } from 'react';
     2→import {
     3→  Tabs,
     4→  Tab,
     5→  TabTitleText,
     6→  Button,
     7→  Tooltip,
     8→} from '@patternfly/react-core';
     9→import { TimesIcon, PlusIcon, FolderOpenIcon } from '@patternfly/react-icons';
    10→import type { Project } from '../state/store';
    11→
    12→interface TabBarProps {
    13→  projects: Project[];
    14→  activeProjectId: string;
    15→  onSelect: (projectId: string) => void;
    16→  onClose: (projectId: string) => void;
    17→  onAdd: () => void;
    18→  onReorder?: (order: string[]) => void;
    19→}
    20→
    21→export function TabBar({
    22→  projects,
    23→  activeProjectId,
    24→  onSelect,
    25→  onClose,
    26→  onAdd,
    27→}: TabBarProps) {
    28→  const [draggedId, setDraggedId] = useState<string | null>(null);
    29→  const tabsRef = useRef<HTMLDivElement>(null);
    30→
    31→  // Focus management after tab changes
    32→  useEffect(() => {
    33→    if (tabsRef.current && activeProjectId) {
    34→      const activeTab = tabsRef.current.querySelector(`[data-tab-id="${activeProjectId}"]`);
    35→      if (activeTab instanceof HTMLElement) {
    36→        activeTab.focus();
    37→      }
    38→    }
    39→  }, [activeProjectId]);
    40→
    41→  const handleSelect = useCallback(
    42→    (_event: React.MouseEvent<HTMLElement>, eventKey: string | number) => {
    43→      if (typeof eventKey === 'string') {
    44→        onSelect(eventKey);
    45→      }
    46→    },
    47→    [onSelect]
    48→  );
    49→
    50→  const handleClose = useCallback(
    51→    (event: React.MouseEvent<HTMLButtonElement>, projectId: string) => {
    52→      event.stopPropagation();
    53→      onClose(projectId);
    54→    },
    55→    [onClose]
    56→  );
    57→
    58→  const handleDragStart = useCallback((e: React.DragEvent, projectId: string) => {
    59→    setDraggedId(projectId);
    60→    e.dataTransfer.effectAllowed = 'move';
    61→    e.dataTransfer.setData('text/plain', projectId);
    62→  }, []);
    63→
    64→  const handleDragOver = useCallback((e: React.DragEvent) => {
    65→    e.preventDefault();
    66→    e.dataTransfer.dropEffect = 'move';
    67→  }, []);
    68→
    69→  const handleDrop = useCallback(
    70→    (e: React.DragEvent, targetId: string) => {
    71→      e.preventDefault();
    72→      const sourceId = e.dataTransfer.getData('text/plain');
    73→      if (sourceId && sourceId !== targetId) {
    74→        // TODO: Implement reorder when connected to state
    75→        console.log('Reorder:', sourceId, '->', targetId);
    76→      }
    77→      setDraggedId(null);
    78→    },
    79→    []
    80→  );
    81→
    82→  const handleDragEnd = useCallback(() => {
    83→    setDraggedId(null);
    84→  }, []);
    85→
    86→  // Empty state when no projects
    87→  if (projects.length === 0) {
    88→    return (
    89→      <div
    90→        style={{
    91→          display: 'flex',
    92→          alignItems: 'center',
    93→          padding: '8px 16px',
    94→          background: 'var(--pf-t--global--background--color--secondary--default)',
    95→          borderBottom: '1px solid var(--pf-t--global--border--color--default)',
    96→        }}
    97→      >
    98→        <Button
    99→          variant="link"
   100→          icon={<FolderOpenIcon />}
   101→          onClick={onAdd}
   102→        >
   103→          Open a project to get started
   104→        </Button>
   105→      </div>
   106→    );
   107→  }
   108→
   109→  return (
   110→    <div ref={tabsRef} style={{ position: 'relative' }}>
   111→      <Tabs
   112→        activeKey={activeProjectId}
   113→        onSelect={handleSelect}
   114→        aria-label="Project tabs"
   115→        role="region"
   116→        isOverflowHorizontal={{ showTabCount: true }}
   117→      >
   118→        {projects.map((project) => (
   119→          <Tab
   120→            key={project.id}
   121→            eventKey={project.id}
   122→            data-tab-id={project.id}
   123→            aria-label={`${project.name} tab`}
   124→            title={
   125→              <div
   126→                style={{
   127→                  display: 'flex',
   128→                  alignItems: 'center',
   129→                  gap: '8px',
   130→                }}
   131→                draggable
   132→                onDragStart={(e) => handleDragStart(e, project.id)}
   133→                onDragOver={handleDragOver}
   134→                onDrop={(e) => handleDrop(e, project.id)}
   135→                onDragEnd={handleDragEnd}
   136→              >
   137→                <TabTitleText>{project.name}</TabTitleText>
   138→                {projects.length > 1 && (
   139→                  <Tooltip content="Close tab">
   140→                    <span
   141→                      role="button"
   142→                      tabIndex={0}
   143→                      aria-label={`Close ${project.name}`}
   144→                      onClick={(e) => handleClose(e as unknown as React.MouseEvent<HTMLButtonElement>, project.id)}
   145→                      onKeyDown={(e) => {
   146→                        if (e.key === 'Enter' || e.key === ' ') {
   147→                          handleClose(e as unknown as React.MouseEvent<HTMLButtonElement>, project.id);
   148→                        }
   149→                      }}
   150→                      style={{
   151→                        padding: '4px',
   152→                        cursor: 'pointer',
   153→                        display: 'inline-flex',
   154→                        alignItems: 'center',
   155→                        borderRadius: '4px',
   156→                        opacity: draggedId === project.id ? 0.5 : 1,
   157→                      }}
   158→                    >
   159→                      <TimesIcon />
   160→                    </span>
   161→                  </Tooltip>
   162→                )}
   163→              </div>
   164→            }
   165→            style={{
   166→              opacity: draggedId === project.id ? 0.5 : 1,
   167→              transition: 'opacity 0.2s',
   168→            }}
   169→          />
   170→        ))}
   171→      </Tabs>
   172→
