     1→import { useEffect, useState, useCallback, useRef } from "react";
     2→import {
     3→  Button,
     4→  Card,
     5→  CardBody,
     6→  CardTitle,
     7→  TextInput,
     8→  Label,
     9→  Flex,
    10→  FlexItem,
    11→  Alert,
    12→  TextInputGroup,
    13→  TextInputGroupMain,
    14→  TextInputGroupUtilities,
    15→} from "@patternfly/react-core";
    16→import { PlayIcon, StopIcon, TerminalIcon, KeyIcon } from "@patternfly/react-icons";
    17→import {
    18→  isTauri,
    19→  isDevBridgeAvailable,
    20→  setDevBridgeToken,
    21→  ptySpawn,
    22→  ptyWrite,
    23→  ptyKill,
    24→  onPtyOutput,
    25→  onPtyExit,
    26→  ProcessInfo,
    27→} from "../lib/rpc";
    28→
    29→type UnlistenFn = () => void;
    30→
    31→interface TerminalPanelProps {
    32→  height?: number;
    33→  defaultCwd?: string;
    34→}
    35→
    36→type BackendMode = "tauri" | "dev-bridge" | "none";
    37→
    38→export function TerminalPanel({
    39→  height = 300,
    40→  defaultCwd,
    41→}: TerminalPanelProps) {
    42→  const [processInfo, setProcessInfo] = useState<ProcessInfo | null>(null);
    43→  const [output, setOutput] = useState<string[]>([]);
    44→  const [input, setInput] = useState("");
    45→  const [status, setStatus] = useState<"idle" | "running" | "stopped">("idle");
    46→  const [backendMode, setBackendMode] = useState<BackendMode>("none");
    47→  const [tokenInput, setTokenInput] = useState("");
    48→  const [showTokenInput, setShowTokenInput] = useState(false);
    49→  const outputRef = useRef<HTMLDivElement>(null);
    50→  const unlistenRef = useRef<UnlistenFn[]>([]);
    51→
    52→  // Check backend availability on mount
    53→  useEffect(() => {
    54→    const checkBackend = async () => {
    55→      if (isTauri()) {
    56→        setBackendMode("tauri");
    57→        return;
    58→      }
    59→
    60→      const devBridgeAvailable = await isDevBridgeAvailable();
    61→      if (devBridgeAvailable) {
    62→        setBackendMode("dev-bridge");
    63→      } else {
    64→        setBackendMode("none");
    65→      }
    66→    };
    67→
    68→    checkBackend();
    69→  }, []);
    70→
    71→  // Auto-scroll to bottom when output changes
    72→  useEffect(() => {
    73→    if (outputRef.current) {
    74→      outputRef.current.scrollTop = outputRef.current.scrollHeight;
    75→    }
    76→  }, [output]);
    77→
    78→  // Setup event listeners when process starts
    79→  useEffect(() => {
    80→    if (!processInfo || backendMode === "none") return;
    81→
    82→    const setupListeners = async () => {
    83→      const unlistenOutput = await onPtyOutput((payload) => {
    84→        if (payload.id === processInfo.id) {
    85→          setOutput((prev) => [...prev, payload.data]);
    86→        }
    87→      });
    88→
    89→      const unlistenExit = await onPtyExit((payload) => {
    90→        if (payload.id === processInfo.id) {
    91→          setStatus("stopped");
    92→          setOutput((prev) => [
    93→            ...prev,
    94→            `\n\x1b[33m[Process exited with code: ${payload.code ?? "unknown"}]\x1b[0m\n`,
    95→          ]);
    96→        }
    97→      });
    98→
    99→      unlistenRef.current = [unlistenOutput, unlistenExit];
   100→    };
   101→
   102→    setupListeners();
   103→
   104→    return () => {
   105→      unlistenRef.current.forEach((unlisten) => unlisten());
   106→      unlistenRef.current = [];
   107→    };
   108→  }, [processInfo, backendMode]);
   109→
   110→  // Handle token submission
   111→  const handleTokenSubmit = useCallback(() => {
   112→    if (tokenInput.trim()) {
   113→      setDevBridgeToken(tokenInput.trim());
   114→      setShowTokenInput(false);
   115→      setTokenInput("");
   116→
   117→      // Re-check backend availability
   118→      isDevBridgeAvailable().then((available) => {
   119→        if (available) {
   120→          setBackendMode("dev-bridge");
   121→          setOutput((prev) => [
   122→            ...prev,
   123→            "\x1b[32m[Token set. Dev bridge connected.]\x1b[0m\n",
   124→          ]);
   125→        }
   126→      });
   127→    }
   128→  }, [tokenInput]);
   129→
   130→  // Spawn a new shell process
   131→  const handleSpawn = useCallback(async () => {
   132→    if (backendMode === "none") {
   133→      setOutput([
   134→        "PTY requires either the native Tauri app or the dev bridge. This feature is not available in the browser without the dev bridge.",
   135→      ]);
   136→      return;
   137→    }
   138→
   139→    try {
   140→      // Detect shell based on platform
   141→      const shell = navigator.userAgent.includes("Mac")
   142→        ? "/bin/zsh"
   143→        : "/bin/bash";
   144→      const cwd = defaultCwd || "/";
   145→
   146→      const info = await ptySpawn(shell, [], cwd, 24, 80);
   147→
   148→      setProcessInfo(info);
   149→      setOutput([
   150→        `\x1b[32m[Shell started: ${info.cmd}]\x1b[0m\n`,
   151→        `\x1b[36m[Mode: ${backendMode === "tauri" ? "Native Tauri" : "Dev Bridge RPC"}]\x1b[0m\n`,
   152→      ]);
   153→      setStatus("running");
   154→    } catch (error) {
   155→      setOutput((prev) => [...prev, `\x1b[31m[Error: ${error}]\x1b[0m\n`]);
   156→    }
   157→  }, [defaultCwd, backendMode]);
   158→
   159→  // Kill the current process
   160→  const handleKill = useCallback(async () => {
   161→    if (!processInfo || backendMode === "none") return;
   162→
   163→    try {
   164→      await ptyKill(processInfo.id);
   165→      setStatus("stopped");
   166→    } catch (error) {
   167→      setOutput((prev) => [...prev, `\x1b[31m[Kill error: ${error}]\x1b[0m\n`]);
   168→    }
   169→  }, [processInfo, backendMode]);
   170→
   171→  // Send command to the process
   172→  const handleSend = useCallback(async () => {
   173→    if (!processInfo || !input.trim() || backendMode === "none") return;
   174→
   175→    try {
   176→      await ptyWrite(processInfo.id, input + "\n");
   177→      setInput("");
   178→    } catch (error) {
   179→      setOutput((prev) => [
   180→        ...prev,
   181→        `\x1b[31m[Write error: ${error}]\x1b[0m\n`,
   182→      ]);
   183→    }
   184→  }, [processInfo, input, backendMode]);
   185→
   186→  // Handle Enter key in input
   187→  const handleKeyDown = useCallback(
   188→    (event: React.KeyboardEvent) => {
   189→      if (event.key === "Enter") {
   190→        handleSend();
   191→      }
   192→    },
   193→    [handleSend]
   194→  );
   195→
   196→  // Handle token input Enter key
   197→  const handleTokenKeyDown = useCallback(
   198→    (event: React.KeyboardEvent) => {
   199→      if (event.key === "Enter") {
   200→        handleTokenSubmit();
   201→      }
   202→    },
   203→    [handleTokenSubmit]
   204→  );
   205→
   206→  // Parse ANSI codes for display
   207→  const parseAnsi = (text: string): string => {
   208→    return text;
   209→  };
   210→
   211→  const isBackendAvailable = backendMode !== "none";
   212→
   213→  return (
   214→    <Card>
   215→      <CardTitle>
   216→        <Flex>
   217→          <FlexItem>
   218→            <TerminalIcon /> Terminal (PTY)
   219→          </FlexItem>
   220→          <FlexItem>
   221→            <Label
   222→              color={
   223→                backendMode === "tauri"
   224→                  ? "blue"
   225→                  : backendMode === "dev-bridge"
   226→                    ? "teal"
   227→                    : "grey"
   228→              }
   229→            >
   230→              {backendMode === "tauri"
   231→                ? "Native"
   232→                : backendMode === "dev-bridge"
   233→                  ? "Dev Bridge"
   234→                  : "No Backend"}
   235→            </Label>
   236→          </FlexItem>
   237→          <FlexItem>
   238→            <Label
   239→              color={
   240→                status === "running"
   241→                  ? "green"
   242→                  : status === "stopped"
   243→                    ? "red"
   244→                    : "grey"
   245→              }
   246→            >
   247→              {status}
   248→            </Label>
   249→          </FlexItem>
   250→        </Flex>
   251→      </CardTitle>
   252→      <CardBody>
   253→        {/* Warning when no backend available */}
   254→        {backendMode === "none" && !showTokenInput && (
   255→          <Alert
   256→            variant="warning"
   257→            title="No Backend Available"
   258→            isInline
   259→            style={{ marginBottom: "8px" }}
   260→            actionLinks={
   261→              <Button
   262→                variant="link"
   263→                onClick={() => setShowTokenInput(true)}
   264→                style={{ paddingLeft: 0 }}
   265→              >
   266→                <KeyIcon /> Set Dev Bridge Token
   267→              </Button>
   268→            }
   269→          >
   270→            PTY requires the native Tauri app or dev bridge connection. Start
   271→            the app with <code>bun tauri dev</code> and copy the token from the
   272→            terminal.
   273→          </Alert>
   274→        )}
   275→
   276→        {/* Token input */}
   277→        {showTokenInput && (
   278→          <div style={{ marginBottom: "8px" }}>
   279→            <TextInputGroup>
   280→              <TextInputGroupMain
   281→                value={tokenInput}
   282→                onChange={(_e, val) => setTokenInput(val)}
   283→                onKeyDown={handleTokenKeyDown}
   284→                placeholder="Paste dev bridge token from terminal..."
   285→                aria-label="Dev bridge token"
   286→              />
   287→              <TextInputGroupUtilities>
   288→                <Button variant="control" onClick={handleTokenSubmit}>
   289→                  Set
   290→                </Button>
   291→                <Button
   292→                  variant="plain"
   293→                  onClick={() => setShowTokenInput(false)}
   294→                >
   295→                  Cancel
   296→                </Button>
   297→              </TextInputGroupUtilities>
   298→            </TextInputGroup>
   299→          </div>
   300→        )}
   301→
   302→        {/* Dev bridge mode info */}
   303→        {backendMode === "dev-bridge" && (
   304→          <Alert
   305→            variant="info"
   306→            title="Dev Bridge Mode"
   307→            isInline
   308→            style={{ marginBottom: "8px" }}
   309→          >
   310→            Connected via RPC bridge. PTY output is streamed over WebSocket.
   311→          </Alert>
   312→        )}
   313→
   314→        {/* Output area */}
   315→        <div
   316→          ref={outputRef}
   317→          style={{
   318→            height: `${height}px`,
