   321→            fontFamily: "monospace",
   322→            fontSize: "13px",
   323→            padding: "8px",
   324→            overflowY: "auto",
   325→            whiteSpace: "pre-wrap",
   326→            borderRadius: "4px",
   327→            marginBottom: "8px",
   328→          }}
